// 容易犯的錯誤寫法
useEffect(async () => {
  const res = await fetch(`/api/user/${userId}`);
  setUser(await res.json());
}, [userId]);

function ChatRoom({ roomId, title }) {
  useEffect(() => {
    document.title = title;
  }, [title]);

  useEffect(() => {
    const connection = createConnection(roomId);
    connection.connect();
    return () => connection.disconnect();
  }, [roomId]);

  return <p>{title}</p>;
}

function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    setCount(count + 1); // 在 effect 裡更新了依賴陣列裡的 count 本身
  }, [count]); // count 變 → effect 重新執行 → 又更新 count → 無限循環

  return <p>{count}</p>;
}
